#include <stdio.h>
#include <pthread.h>

#define ARRAY_SIZE 9
#define NUM_SEGMENTS 3

int arr[ARRAY_SIZE] = {1,2,3,4,5,6,7,8,9};
int segmentSums[NUM_SEGMENTS];

void* worker(void* arg) {
    int seg = *(int*)arg;
    int start = seg * (ARRAY_SIZE / NUM_SEGMENTS);
    int end = start + (ARRAY_SIZE / NUM_SEGMENTS);
    int sum = 0;
    for (int i = start; i < end; ++i) sum += arr[i];
    segmentSums[seg] = sum;
    return NULL;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        pthread_t threads[NUM_SEGMENTS];
        int ids[NUM_SEGMENTS];
        for (int i = 0; i < NUM_SEGMENTS; ++i) {
            ids[i] = i;
            pthread_create(&threads[i], NULL, worker, &ids[i]);
        }
        for (int i = 0; i < NUM_SEGMENTS; ++i) pthread_join(threads[i], NULL);
        int total = segmentSums[0] + segmentSums[1] + segmentSums[2];
        printf("Segment 0 Sum: %d\n", segmentSums[0]);
        printf("Segment 1 Sum: %d\n", segmentSums[1]);
        printf("Segment 2 Sum: %d\n", segmentSums[2]);
        printf("Total Sum: %d\n", total);
        if (tc != T-1) printf("\n");
    }
    return 0;
}

