code.Java:
import java.util.*;

public class Main {
    private static final int ARRAY_SIZE = 9;
    private static final int NUM_SEGMENTS = 3;
    private static final int[] arr = {1,2,3,4,5,6,7,8,9};
    private static final int[] segmentSums = new int[NUM_SEGMENTS];

    private static void calculateSegmentSum(int segmentId) {
        int start = segmentId * (ARRAY_SIZE / NUM_SEGMENTS);
        int end = start + (ARRAY_SIZE / NUM_SEGMENTS);
        int sum = 0;
        for (int i = start; i < end; ++i) sum += arr[i];
        segmentSums[segmentId] = sum;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.hasNextInt() ? sc.nextInt() : 0;
        for (int tc = 0; tc < T; ++tc) {
            Thread[] threads = new Thread[NUM_SEGMENTS];
            for (int i = 0; i < NUM_SEGMENTS; ++i) {
                final int seg = i;
                threads[i] = new Thread(() -> calculateSegmentSum(seg));
                threads[i].start();
            }
            for (Thread t : threads) {
                try { t.join(); } catch (InterruptedException e) { e.printStackTrace(); }
            }
            int total = segmentSums[0] + segmentSums[1] + segmentSums[2];
            System.out.println("Segment 0 Sum: " + segmentSums[0]);
            System.out.println("Segment 1 Sum: " + segmentSums[1]);
            System.out.println("Segment 2 Sum: " + segmentSums[2]);
            System.out.println("Total Sum: " + total);
            if (tc != T-1) System.out.println();
        }
        sc.close();
    }
}

