const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length===0) process.exit(0);
const T = parseInt(input[0],10);
const ARRAY = [1,2,3,4,5,6,7,8,9];
const NUM_SEGMENTS = 3;
const SEG_SIZE = ARRAY.length/NUM_SEGMENTS;
function segmentSum(seg){
  let start = seg*SEG_SIZE;
  let end = start+SEG_SIZE;
  let sum=0;
  for(let i=start;i<end;i++) sum+=ARRAY[i];
  return sum;
}
let outputs=[];
for(let tc=0; tc<T; ++tc){
  let segSums = [];
  for(let i=0;i<NUM_SEGMENTS;i++) segSums[i]=segmentSum(i);
  let total = segSums.reduce((a,b)=>a+b,0);
  let lines = [];
  for(let i=0;i<NUM_SEGMENTS;i++) lines.push(`Segment ${i} Sum: ${segSums[i]}`);
  lines.push(`Total Sum: ${total}`);
  outputs.push(lines.join('\n'));
